from typing import List

class Solution:
    def maxSubArray(self, nums: List[int]) -> None:
        if not nums:
            return

        max_sum = float('-inf')
        current_sum = 0
        start = 0
        max_start = 0
        max_end = 0

        for i in range(len(nums)):
            if current_sum <= 0:
                current_sum = nums[i]
                start = i
            else:
                current_sum += nums[i]

            if current_sum > max_sum:
                max_sum = current_sum
                max_start = start
                max_end = i

        print(max_sum)
        print(' '.join(map(str, nums[max_start:max_end + 1])))

