#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    void maxSubArray(vector<int>& nums) {
        if (nums.empty()) {
            return;
        }

        int max_sum = INT_MIN;
        int current_sum = 0;
        int start = 0;
        int max_start = 0;
        int max_end = 0;

        for (int i = 0; i < nums.size(); i++) {
            if (current_sum <= 0) {
                current_sum = nums[i];
                start = i;
            } else {
                current_sum += nums[i];
            }

            if (current_sum > max_sum) {
                max_sum = current_sum;
                max_start = start;
                max_end = i;
            }
        }

        cout << max_sum << '\n';
        for (int i = max_start; i <= max_end; i++) {
            cout << nums[i] << (i == max_end ? '\n' : ' ');
        }
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    sol.maxSubArray(nums);
    return 0;
}
